//! # helix-demo — the synthetic "Alex Rivera" demo dossier
//!
//! ⚠️ **SAMPLE / SYNTHETIC DATA — NOT A REAL PERSON.** ⚠️
//!
//! Everything in this crate is *fiction*. "Alex Rivera" is an invented persona
//! whose numbers were generated by the deterministic functions below — no real
//! health data of any kind was read, copied, or used to build it. It exists so
//! that anyone who clones the **public** Helix repo sees the full product
//! experience (dashboard, score, ask, report, focus areas, bio-age) across all
//! six data domains, with a story that hangs together.
//!
//! It is the source of truth for `ui/demo-dossier.json` (regenerate with
//! `cargo run -p helix-demo --example generate`). The records are real
//! [`ProvRecord`]s, so they flow through the *real* anti-hallucination pipeline
//! (`helix-pipeline::analyze`, `helix-focus`, `helix-score`, `helix-bioage`,
//! `helix-timeline`) — nothing about the demo is mocked. See the tests.
//!
//! ## The persona (fiction)
//! Alex Rivera, ~45, is on a health push. The data tells ONE coherent story:
//! - **Mild iron deficiency** (ferritin low, rechecked, slowly recovering on a
//!   supplement) → the afternoon-fatigue thread.
//! - **Suboptimal deep sleep on late-training nights** (evening strength/cardio
//!   sessions push bedtime late → less deep sleep, lower HRV, higher resting HR).
//! - **Improving body composition on a fitness push** (weight ↓, body-fat ↓,
//!   skeletal muscle ↑, resting HR ↓, steps ↑).
//! - **Borderline lipids** (LDL/ApoB above optimal but improving on lifestyle +
//!   a low-dose statin).
//!
//! All acute/critical markers (potassium, glucose, haemoglobin, SpO₂) sit safely
//! inside range, so the demo shows grounded optimisation answers, not an alarm.
//!
//! Dates are anchored to a fixed reference (2026-06-01) and go back ~90 days, so
//! the demo is fully deterministic and reproducible.

use serde::Serialize;
use serde_json::{json, Value};

use helix_provenance::{Confidence, MeasurementMethod, ProvRecord, RecordId, ReferenceRange};

/// One day in milliseconds.
pub const DAY: i64 = 86_400_000;

/// Fixed reference "now": 2026-06-01T00:00:00Z. All records are dated relative to
/// this so the demo never depends on the wall clock (matches ADR-007's
/// clock-injection discipline). Verified: `Date.UTC(2026, 5, 1) == 1_780_272_000_000`.
pub const ANCHOR_MS: i64 = 1_780_272_000_000;

/// Length of the demo window in days (record dates span `[ANCHOR-89d, ANCHOR]`).
pub const SPAN_DAYS: i64 = 90;

/// The banner that must travel with the demo data everywhere it is shown.
pub const DISCLAIMER: &str = "SAMPLE / SYNTHETIC DATA — NOT A REAL PERSON. \
    'Alex Rivera' is a fictional persona; every value here was generated \
    deterministically for demonstration only and must never be read as medical fact.";

// ---------------------------------------------------------------------------
// Deterministic pseudo-randomness (dependency-free, reproducible).
// ---------------------------------------------------------------------------

/// SplitMix64 — a tiny, well-mixed hash so per-day jitter is reproducible.
fn hash64(mut x: u64) -> u64 {
    x = x.wrapping_add(0x9E37_79B9_7F4A_7C15);
    x = (x ^ (x >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
    x = (x ^ (x >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
    x ^ (x >> 31)
}

/// Reproducible jitter in `[-amp, amp]` from a metric salt and a day index.
fn jitter(salt: u64, day: i64, amp: f64) -> f64 {
    if amp == 0.0 {
        return 0.0;
    }
    let h = hash64(salt ^ (day as u64).wrapping_mul(0x1000_0001B3));
    let u = (h as f64) / (u64::MAX as f64); // [0,1]
    (u * 2.0 - 1.0) * amp
}

fn round_to(v: f64, decimals: u32) -> f64 {
    let f = 10f64.powi(decimals as i32);
    (v * f).round() / f
}

/// Timestamp for `days_before` the anchor (`0` == anchor / most recent).
fn day_ms(days_before: i64) -> i64 {
    ANCHOR_MS - days_before * DAY
}

/// Progress through the window: `0.0` at the oldest day, `1.0` at the anchor.
fn progress(days_before: i64) -> f64 {
    (SPAN_DAYS - 1 - days_before) as f64 / (SPAN_DAYS - 1) as f64
}

fn lerp(start: f64, end: f64, p: f64) -> f64 {
    start + (end - start) * p
}

/// Program day-of-week (0..6) for a given `days_before` — drives the training
/// schedule and the "late-night workout hurts deep sleep" correlation.
fn program_dow(days_before: i64) -> i64 {
    (SPAN_DAYS - 1 - days_before).rem_euclid(7)
}

/// Late (evening) training nights: Tue (dow 2) & Fri (dow 5). These nights get a
/// deep-sleep / HRV penalty in the wearable series — the encoded correlation.
fn is_late_training(days_before: i64) -> bool {
    matches!(program_dow(days_before), 2 | 5)
}

// ---------------------------------------------------------------------------
// Record builder.
// ---------------------------------------------------------------------------

#[allow(clippy::too_many_arguments)]
fn rec(
    id: String,
    source: &str,
    measured_at: i64,
    method: MeasurementMethod,
    code: Option<&str>,
    concept: &str,
    value: f64,
    unit: &str,
    low: Option<f64>,
    high: Option<f64>,
    confidence: f64,
) -> ProvRecord {
    let reference_range = if low.is_some() || high.is_some() {
        Some(ReferenceRange::new(low, high))
    } else {
        None
    };
    ProvRecord {
        id: RecordId::from(id),
        source: source.to_string(),
        measured_at,
        method,
        code: code.map(|c| c.to_string()),
        concept: concept.to_string(),
        value,
        unit: unit.to_string(),
        reference_range,
        confidence: Confidence::new(confidence),
    }
}

// ---------------------------------------------------------------------------
// Domain 1 (part) + wearable daily series (Apple Watch / Apple Health).
// ---------------------------------------------------------------------------

/// A daily-sampled metric with a gentle start→end trend plus reproducible jitter.
struct Daily {
    id_prefix: &'static str,
    code: &'static str,
    concept: &'static str,
    unit: &'static str,
    source: &'static str,
    method: MeasurementMethod,
    start: f64,
    end: f64,
    amp: f64,
    /// Delta applied on late-training nights (negative = worse recovery).
    late_delta: f64,
    low: Option<f64>,
    high: Option<f64>,
    /// Hard clamp applied after jitter (keeps e.g. SpO₂ safely above red-flags).
    clamp: Option<(f64, f64)>,
    decimals: u32,
    salt: u64,
}

fn daily_series(m: &Daily, out: &mut Vec<ProvRecord>) {
    for d in (0..SPAN_DAYS).rev() {
        // d = days before anchor; iterate oldest → newest for readable ids.
        let p = progress(d);
        let mut v = lerp(m.start, m.end, p) + jitter(m.salt, d, m.amp);
        if m.late_delta != 0.0 && is_late_training(d) {
            v += m.late_delta;
        }
        if let Some((lo, hi)) = m.clamp {
            v = v.clamp(lo, hi);
        }
        out.push(rec(
            format!("{}-{}", m.id_prefix, d),
            m.source,
            day_ms(d),
            m.method,
            Some(m.code),
            m.concept,
            round_to(v, m.decimals),
            m.unit,
            m.low,
            m.high,
            0.95,
        ));
    }
}

