fn workouts(out: &mut Vec<ProvRecord>) {
    for d in (0..SPAN_DAYS).rev() {
        let (name, base, salt) = match program_dow(d) {
            0 => ("Zone 2 run", 52.0, 0xB0u64), // Sun long easy run (AM)
            2 => ("Strength — full body", 50.0, 0xB2), // Tue (evening / late)
            4 => ("Strength — upper/lower", 46.0, 0xB4), // Thu (AM)
            5 => ("Zone 2 cycling", 56.0, 0xB5), // Fri (evening / late)
            _ => continue,
        };
        let mins = round_to(base + jitter(salt, d, 6.0), 0);
        out.push(rec(
            format!("ah-workout-{d}"),
            "Apple Watch",
            day_ms(d),
            MeasurementMethod::Device,
            Some("HK-WORKOUT"),
            &format!("Workout — {name}"),
            mins,
            "min",
            None,
            None,
            0.95,
        ));
    }
}

