fn renpho_records(out: &mut Vec<ProvRecord>) {
    let panel = renpho_panel();
    for d in (0..SPAN_DAYS).rev() {
        if d % 3 != 0 {
            continue; // full body-comp scan every 3 days
        }
        let p = progress(d);
        for (i, m) in panel.iter().enumerate() {
            let (id, code, concept, unit, start, end, amp, dec, low, high) = *m;
            let salt = 0xD000 ^ (i as u64);
            let v = lerp(start, end, p) + jitter(salt, d, amp);
            out.push(rec(
                format!("{id}-{d}"),
                "RENPHO",
                day_ms(d),
                MeasurementMethod::Device,
                Some(code),
                concept,
                round_to(v, dec),
                unit,
                low,
                high,
                0.9,
            ));
        }
    }
}

