fn lab_records(out: &mut Vec<ProvRecord>) {
    for (loinc, concept, unit, low, high, a, b) in lab_panel() {
        out.push(rec(
            format!("lab-{loinc}-A"),
            "Quest Diagnostics",
            day_ms(DRAW_A),
            MeasurementMethod::LabFeed,
            Some(loinc),
            concept,
            a,
            unit,
            low,
            high,
            1.0,
        ));
        if let Some(bv) = b {
            out.push(rec(
                format!("lab-{loinc}-B"),
                "Quest Diagnostics",
                day_ms(DRAW_B),
                MeasurementMethod::LabFeed,
                Some(loinc),
                concept,
                bv,
                unit,
                low,
                high,
                1.0,
            ));
        }
    }
    // Ferritin: low → rechecked twice, slowly recovering on iron (still marginal).
    for (id, day, val) in [
        ("lab-2276-4-A", DRAW_A, 22.0),
        ("lab-2276-4-mid", 40, 26.0),
        ("lab-2276-4-B", DRAW_B, 29.0),
    ] {
        out.push(rec(
            id.to_string(),
            "Quest Diagnostics",
            day_ms(day),
            MeasurementMethod::LabFeed,
            Some("2276-4"),
            "Ferritin",
            val,
            "ng/mL",
            Some(30.0),
            Some(400.0),
            1.0,
        ));
    }
}

